queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?stockbrokers a :Stockbrokers .
    ?stockbrokers p:name ?name .
    ?stockbrokers p:fees ?fees_f .
    FILTER(STR(?fees_f) = "1%")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?mutual_funds a :Mutual_funds .
    ?mutual_funds p:fund_name ?fund_name .
    ?mutual_funds p:fees ?fees_f .
    FILTER(STR(?fees_f) = "1%")
    BIND(?fund_name AS ?o0)
  }
}

